import test from 'node:test';
import assert from 'node:assert/strict';

import { resetFlights } from '../src/inflight.ts';
import { loadUser } from '../src/user_service.ts';

test('failed operation is observable and does not poison retry', async () => {
  resetFlights();
  let calls = 0;
  const provider = async () => {
    calls += 1;
    if (calls === 1) throw new Error('temporary provider failure');
    return 'recovered';
  };
  await assert.rejects(() => loadUser('u-2', provider), /temporary provider failure/);
  const timeout = Symbol('timeout');
  const retryResult = await Promise.race([
    loadUser('u-2', provider),
    new Promise((resolve) => setTimeout(() => resolve(timeout), 100)),
  ]);
  assert.notEqual(retryResult, timeout, 'retry must terminate instead of waiting on its own cached promise');
  assert.equal(retryResult, 'recovered');
  assert.equal(calls, 2);
});
